es_hits.command:
curl -s -X POST 'http://elasticsearch:9200/_query?format=json' \
  -H 'Content-Type: application/json' \
  -d '{
    "query": "FROM agent-logs-* | WHERE event_type == \"skill_index_assembled\" AND @timestamp > NOW()-1hour | SORT @timestamp ASC | LIMIT 50"
  }' | jq '{columns: [.columns[].name], rows: .values}'

